INSERT INTO public.photos VALUES (26024, 'Ctra. de Logroâ”œâ–’o c.1926', 'Periferia agrâ”œÂ¡cola entre el talud del ferrocarril de Madrid a la izquierda, y la carretera de Logroâ”œâ–’o a la derecha y fuera de plano, desde la confluencia de las lâ”œÂ¡neas telefâ”œâ”‚nicas de San Sebastiâ”œÃ­n-Zaragoza y Madrid-Zaragoza. Al fondo, telâ”œâ”‚n de fondo de la ciudad desde las chimeneas del gran complejo de la Industrial Quâ”œÂ¡mica de Zaragoza, pasando por las torres del templo del Pilar, de la Seo, la Torre Mayor de la Aljaferâ”œÂ¡a y la torre de san Pablo Apâ”œâ”‚stol, hasta las câ”œâ•‘pulas de Santiago el Mayor y del Hospicio Provincial.', 1926, 1926, 1926, 'Anos 20', 'LA ALMOZARA', 41.66073300, -0.91909400, '0101000020E6100000F564FED13769EDBFA93121E692D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28410749239.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28410749239.webp', 'https://www.flickr.com/photos/zaragozaantigua/28410749239/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26034, 'Cicatriz 2006', 'Vista del cubrimiento de las vâ”œÂ¡as fâ”œÂ®rreas en agosto de 2006, entre la estaciâ”œâ”‚n Zaragoza Delicias y el tâ”œâ•‘nel de la calle Iriarte Reinoso (ambos hitos fuera de plano, a izquierda y derecha). Era un tramo de 350 metros que discurrâ”œÂ¡a bajo los actuales solares (previsto paseo del Agua) entre la calle de Antonio Cano Mata y avenida de la Ciudad de Soria. Al fondo, barrio de La Almozara, que supuestamente vio cerrada la pretendida cicatriz del tendido ferroviario en 2008, aunque la uniâ”œâ”‚n con el barrio de Las Delicias no acabâ”œâ”‚ de ser suturada; antes bien, la herida permanece en 2017 pese a la sepultura de las traviesas. El entorno se abriâ”œâ”‚ al trâ”œÃ­fico rodado en 2008. Fuente: Heraldo de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', 'LA ALMOZARA', 41.65755200, -0.90634200, '0101000020E61000002CB81FF0C000EDBFAFB5F7A92AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31192050994.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31192050994.webp', 'https://www.flickr.com/photos/zaragozaantigua/31192050994/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20882, 'Aljaferâ”œÂ¡a 1328', 'Neorromâ”œÃ­ntico dibujo realizado por Fernando Fernâ”œÃ­ndez Mota en 1917 con pretensiâ”œâ”‚n de ilustrar los festejos y ceremoniales habidos en la ciudad el pascual domingo de 1328 durante la coronaciâ”œâ”‚n de Alfonso IV como rey de Aragâ”œâ”‚n. La idealizada imagen representa la matacâ”œÂ¡a de toros ejecutada en un provisional recinto habilitado para la ocasiâ”œâ”‚n en la huerta del Rey, inmediata a la Aljaferâ”œÂ¡a. Segâ”œâ•‘n cuenta la Crâ”œâ”‚nica de Muntaner, Alfonso IV tomâ”œâ”‚ solemnemente la corona del Reino de Aragâ”œâ”‚n en la catedral de San Salvador y despuâ”œÂ®s fue acompaâ”œâ–’ado en grandiosa manifestaciâ”œâ”‚n hasta la Aljaferâ”œÂ¡a, donde tuvieron lugar diversas muestras y exhibiciones a caballo que incluyeron el lanceo y muerte de toros, uno por cada una de las cristianas parroquias de la ciudad. Fuente visual: www.delcampe.net', 1328, 1328, 1328, 'Siglo XIX', 'LA ALMOZARA', 41.65807200, -0.89782900, '0101000020E6100000F2CF0CE203BBECBFE7340BB43BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24457717138.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24457717138.webp', 'https://www.flickr.com/photos/zaragozaantigua/24457717138/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20962, 'Vista general de Zaragoza 1806', 'L.F. Lejeune/A. Hulk. 1806. "Vista general de Zaragoza. Vue gâ”œÂ®nâ”œÂ®rale de Saragosse. General View of Saragossa", incluido en Alexandre de Laborde, "Voyage pittoresque et historique en Espagne", Parâ”œÂ¡s, Pierre Didot l''ainâ”œÂ®, 1806-1820. El dibujo se ha realizado desde la ribera izquierda del Ebro, a la altura de la Aljaferâ”œÂ¡a, en lo que hoy serâ”œÂ¡a la confluencia de la Avenida de Ranillas con Clara Campoamor. De derecha a izquierda, en primer lugar, aspecto de las fachadas norte y oeste del castillo de la Aljaferâ”œÂ¡a, aâ”œâ•‘n con sus fachadas barrocas, y la barroca torre (completa) de la capilla de San Martâ”œÂ¡n. Despuâ”œÂ®s, un barrido por la lâ”œÂ¡nea del horizonte de la ciudad: la Misericordia, San Pablo, San Ildefonso, Escolapios, Santa Isabel, San Francisco, la Torre Nueva, San Juan de los Panetes, la Seo, y el Pilar. Al fondo a la izquierda, el puente de Piedra y la Iglesia de Altabâ”œÃ­s. Fuente: "La Aljaferâ”œÂ¡a", Cortes de Aragâ”œâ”‚n, 1998.', 1806, 1806, 1806, 'Siglo XIX', 'LA ALMOZARA', 41.66685300, -0.89448400, '0101000020E6100000CD72D9E89C9FECBFA81E69705BD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15513193652.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15513193652.webp', 'https://www.flickr.com/photos/zaragozaantigua/15513193652/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21225, 'Aljaferâ”œÂ¡a 1900', 'Posado grupal capturado junto a la arboleda al norte del cuartel de la Aljaferâ”œÂ¡a. Al fondo, la silueta del antiguo "palacio de la Alegrâ”œÂ¡a", de la que destaca la poderosa Torre del Trovador, cubierta con tejado a varias vertientes. A su izquierda, la desmochada torre neoclâ”œÃ­sica de la iglesia de San Martâ”œÂ¡n, que antes fuera alminar. A la fachada norte del ahora cuartel le han sido adosadas unas bajas construcciones en las que dar mejor cabida a los pertrechos cuartelarios. Justo delante cruza el tendido ferroviario que por el Puente sobre el Ebro conecta con la estaciâ”œâ”‚n del Norte, o Arrabal. Al pie de los â”œÃ­rboles, fluye la antigua acequia mayor de la Almozara, como en siglos anteriores, hacia la Puerta de Sancho, que sigue aâ”œâ•‘n en pie, junto a los viveros del Ayuntamiento. Fuente visual: quintodeebro.com/ Familia Florencio Jardiel Dobato', 1900, 1900, 1900, 'Anos 1900', 'LA ALMOZARA', 41.65866100, -0.89630800, '0101000020E6100000D594641D8EAEECBF4913EF004FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16354313707.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16354313707.webp', 'https://www.flickr.com/photos/zaragozaantigua/16354313707/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21276, 'La Almozara 1908', 'Imagen desde notable altura capturada por una câ”œÃ­mara instalada en el globo-cometa "Marâ”œÂ¡a Cristina", durante unas maniobras en Zaragoza de la Escuela Prâ”œÃ­ctica de las tropas de aeroestaciâ”œâ”‚n y alumbrado en campaâ”œâ–’a del Ejâ”œÂ®rcito, a finales del mes de agosto. La imagen se corresponde con el râ”œÂ¡o Ebro y un puente tendido por el regimiento de pontoneros de la ciudad. Al norte, la margen izquierda, con aspecto de la huerta, campos y camino de Ranillas. Al sur, la margen derecha, con el soto y el camino de la Almozara, ademâ”œÃ­s de la zona de prâ”œÃ­ctica de pontoneros. Fuente visual: "Espaâ”œâ–’a Automâ”œâ”‚vil. Revista tâ”œÂ®cnica de automovilismo y aeronâ”œÃ­utica".', 1908, 1908, 1908, 'Anos 1900', 'LA ALMOZARA', 41.66705200, -0.90008300, '0101000020E61000002CF015DD7ACDECBF9E5DBEF561D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23442341413.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23442341413.webp', 'https://www.flickr.com/photos/zaragozaantigua/23442341413/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21277, 'Almozara 1908', 'Imagen en altura capturada por una câ”œÃ­mara instalada en el globo-cometa "Marâ”œÂ¡a Cristina", durante unas maniobras en Zaragoza de la Escuela Prâ”œÃ­ctica de las tropas de aeroestaciâ”œâ”‚n y alumbrado en campaâ”œâ–’a del Ejâ”œÂ®rcito, a finales del mes de agosto de ese aâ”œâ–’o. La imagen se corresponde con un vistazo a la ciudad desde el poniente. En primer tâ”œÂ®rmino, el puente del ferrocarril sobre el Ebro, el camino de la Almozara, y la vasta extensiâ”œâ”‚n de la Industrial Quâ”œÂ¡mica, con sus humeantes chimeneas. Como una gran mancha blanca, el casco urbano de la ciudad, del que emergen algunas de sus torres y câ”œâ•‘pulas mâ”œÃ­s seâ”œâ–’aladas, como las de la Misericordia, Santiago, San Pablo, la Seo, y el Pilar, junto al perfilado puente de Piedra. Tras la toma de esta imagen, una formidable tormenta de verano destrozâ”œâ”‚ el globo-cometa, e hizo explotar su gas en el aire, lo que provocâ”œâ”‚ el incendio de un cercano almacâ”œÂ®n de maderas. Fuente visual: "Espaâ”œâ–’a Automâ”œâ”‚vil. Revista tâ”œÂ®cnica de automovilismo y aeronâ”œÃ­utica".', 1908, 1908, 1908, 'Anos 1900', 'LA ALMOZARA', 41.65923800, -0.89545300, '0101000020E6100000E25CC30C8DA7ECBFE62329E961D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24069700345.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24069700345.webp', 'https://www.flickr.com/photos/zaragozaantigua/24069700345/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21302, 'Râ”œÂ¡o Ebro 1900', 'Imagen de un laâ”œâ•‘d, pequeâ”œâ–’a embarcaciâ”œâ”‚n de transporte caracterâ”œÂ¡stica del Ebro, maniobrando junto a la orilla inmediata a la zona de la Almozara. De fondo, el puente del ferrocarril y la pequeâ”œâ–’a arboleda ribereâ”œâ–’a de la Hortilla, en la margen izquierda. Fuente visual: "Zaragoza, orillas del Ebro", postal nâ”¬â•‘ 98 de la serie "Zaragoza" editada y publicada por la fototipia de Lucas Escolâ”œÃ­ para la Uniâ”œâ”‚n Postal Universal, en www.ebay.es/', 1900, 1900, 1900, 'Anos 1900', 'LA ALMOZARA', 41.66186100, -0.89181100, '0101000020E61000005BD1E638B789ECBFBABF7ADCB7D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33661795873.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33661795873.webp', 'https://www.flickr.com/photos/zaragozaantigua/33661795873/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21304, 'Râ”œÂ¡o Ebro 1900', 'Imagen centrada en unas barcas estacionadas junto a la orilla derecha del Ebro, donde el Soto de la Almozara. Al fondo, el puente del ferrocarril y la Ortilla, de la que emerge, posiblemente, la chimenea de la Azucarera de Aragâ”œâ”‚n. Fuente visual: "Zaragoza. Orillas del Ebro", postal nâ”¬â•‘ 94 de la serie "Zaragoza" editada y publicada por la fototipia de Lucas Escolâ”œÃ­ para la Uniâ”œâ”‚n Postal Universal, en www.ebay.es/', 1900, 1900, 1900, 'Anos 1900', 'LA ALMOZARA', 41.66568700, -0.89656300, '0101000020E61000007CB779E3A4B0ECBFA92F4B3B35D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34174048960.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34174048960.webp', 'https://www.flickr.com/photos/zaragozaantigua/34174048960/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21494, 'Pontoneros 1921', '"Escuelas prâ”œÃ­cticas en el Soto de la Almozara", 1921. Construcciâ”œâ”‚n de un puente efâ”œÂ¡mero sobre el râ”œÂ¡o Ebro desde el antiguo camino de Ranillas (actual avenida de Josâ”œÂ® Atarâ”œÂ®s), y hasta el destacamento de Pontoneros de la margen derecha (actual Club Militar el Soto). En la inmortal ciudad, la presencia castrense es constante, imborrable. Fuente: www.facebook.com/photo.php?fbid=10203727419080586&set...', 1921, 1921, 1921, 'Anos 20', 'LA ALMOZARA', 41.66662800, -0.89592900, '0101000020E61000002A37514B73ABECBF884CF91054D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15252995688.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15252995688.webp', 'https://www.flickr.com/photos/zaragozaantigua/15252995688/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21571, 'La Quâ”œÂ¡mica c.1920', 'Los niâ”œâ–’os "de la carbonilla" eran asâ”œÂ¡ denominados porque se apostaban en las inmediaciones de los paraderos y estaciones de ferrocarril, a la rebusca de las escorias y montoneras de restos de carbâ”œâ”‚n que se acumulaban junto a las vâ”œÂ¡as. En ocasiones, incluso, se precipitaban sobre los pequeâ”œâ–’os restos de carbâ”œâ”‚n aâ”œâ•‘n entre incandescencias, los apartaban, dejaban que se enfriaran, y los recogâ”œÂ¡an. El producto final se guardaba en sacos de arpillera para su posterior reutilizaciâ”œâ”‚n, bien domâ”œÂ®stica, o para su venta. En la imagen, uno de esos depâ”œâ”‚sitos a modo de cantera de carbonilla, en un paradero inmediato al tendido del ferrocarril a Alsasua. Al fondo, a la izquierda, el enorme complejo de la "Industrial Quâ”œÂ¡mica de Zaragoza, S. A." en la Almozara. Niâ”œâ–’os y mayores, en la faena de recolecciâ”œâ”‚n de la carbonilla. Fuente visual: Archivo fotogrâ”œÃ­fico histâ”œâ”‚rico del SIPA (DARA-AHPZ).', 1920, 1920, 1920, 'Anos 20', 'LA ALMOZARA', 41.65807200, -0.89782900, '0101000020E6100000F2CF0CE203BBECBFE7340BB43BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23862007361.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23862007361.webp', 'https://www.flickr.com/photos/zaragozaantigua/23862007361/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21838, 'C.â”¬â•‘ de Monzalbarba 1931', 'Imagen capturada en la puerta principal de ingreso a la fâ”œÃ­brica de la Industrial Quâ”œÂ¡mica de Zaragoza SA, con una secciâ”œâ”‚n de caballerâ”œÂ¡a de la Guardia Civil en primer tâ”œÂ®rmino vigilando por orden del gobernador el acceso durante un conflicto entre obreros y patronal de esta empresa. La puerta se abrâ”œÂ¡a en el tramo inicial del camino de Monzalbarba, a poca distancia del apeadero ferroviario de la Quâ”œÂ¡mica. Al fondo, a la izquierda, tejados de la iglesia y convento de las Carmelitas Descalzas de Santa Teresa de Jesâ”œâ•‘s, o Fecetas, en la calle del Veintinueve de Septiembre. Fuente visual: www.mecd.gob.es/.', 1931, 1931, 1931, 'Anos 30', 'LA ALMOZARA', 41.65956100, -0.89400000, '0101000020E6100000CFF753E3A59BECBFC85BAE7E6CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34817331573.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34817331573.webp', 'https://www.flickr.com/photos/zaragozaantigua/34817331573/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22124, 'P.â”¬â•‘ de Marâ”œÂ¡a Agustâ”œÂ¡n 1951', 'Imagen del descendente desde el Portillo paseo de Marâ”œÂ¡a Agustâ”œÂ¡n en su tramo final, donde se convertâ”œÂ¡a en el principio del paseo del Ebro, lugar desde donde se ha realizado la captura fotogrâ”œÃ­fica. A la izquierda, el final de la calle de Santa Lucâ”œÂ¡a, antigua del 29 de septiembre, donde estuviera hasta 1904 la Puerta de Sancho. En ese tramo de la calle, a un lado quedaba el convento de las Fecetas, y al otro, la Alcoholera Agrâ”œÂ¡cola del Pilar. Al fondo, despunta la desmochada torre de la iglesia de San Martâ”œÂ¡n y la cubierta Torre del Homenaje de la Aljaferâ”œÂ¡a, aâ”œâ•‘n como cuartel del ejâ”œÂ®rcito. Los inmediatos edificios de la derecha son almacenes y transformadores elâ”œÂ®ctricos, junto a la callecita que conduce primero al apeadero de la Quâ”œÂ¡mica y el paso a nivel del ferrocarril a Alsasua, y despuâ”œÂ®s a los caminos de Monzalbarba y de la Almorara, en el comienzo del barrio de la Quâ”œÂ¡mica. Fuente visual: Juan Mora Insa, AMZ.', 1951, 1951, 1951, 'Anos 50', 'LA ALMOZARA', 41.65889000, -0.89257200, '0101000020E6100000F568AA27F38FECBFAAD4EC8156D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22778755707.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22778755707.webp', 'https://www.flickr.com/photos/zaragozaantigua/22778755707/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22363, 'Puente del Ferrocarril 1961', 'Foto: Josâ”œÂ® Ignacio Lorenzo. Vista del Pilar a lo lejos desde el puente del Ferrocarril, hoy de La Almozara. Fuente: www.facebook.com/photo.php?fbid=932772793440819&set=g...', 1961, 1961, 1961, 'Anos 60', 'LA ALMOZARA', 41.66069200, -0.89114100, '0101000020E6100000D6FD63213A84ECBF4A5D328E91D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21241870052.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21241870052.webp', 'https://www.flickr.com/photos/zaragozaantigua/21241870052/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22645, 'La Almozara 1970', 'Vista aâ”œÂ®rea del barrio de la Almozara de Zaragoza en 1970, antes de los grandes cambios producidos en la zona. En la actual plaza de Europa, el apeadero del ferrocarril de la Almozara, de la Industrial Quâ”œÂ¡mica. Abajo a la derecha, restos de la Azucarera Agrâ”œÂ¡cola del Pilar. Fuente: Confederaciâ”œâ”‚n Hidrogrâ”œÃ­fica del Ebro.', 1970, 1970, 1970, 'Anos 70', 'LA ALMOZARA', 41.65933200, -0.89244700, '0101000020E6100000DA39CD02ED8EECBF679AB0FD64D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20627908061.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20627908061.webp', 'https://www.flickr.com/photos/zaragozaantigua/20627908061/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22746, 'Almozara 1978', 'Imagen de la Almozara capturada desde el terraplâ”œÂ®n de la moderna autopista A-68, con interesante vista de esta parte del barrio. En primer tâ”œÂ®rmino, las traseras de los impares de la calle Pedro I de Aragâ”œâ”‚n, entonces un conjunto de naves y almacenes. Frente a ellos, los bloques edilicios del nâ”¬â•‘ 12 (esquinero con calle Reina Felicia) y el nâ”¬â•‘ 8 de esa calle, y la estructura del nâ”¬â•‘ 6 en construcciâ”œâ”‚n (ambos, esquineros con la calle Râ”œÂ¡o Duero), como su inmediato y gran bloque de los nâ”œâ•‘meros 46 a 50 de la calle Reino. En el centro de la imagen, las instalaciones de la Industrial Quâ”œÂ¡mica, de las que emerge, mâ”œÃ­s al fondo, el remate de la torre de la iglesia parroquial de San Pablo apâ”œâ”‚stol. A la derecha, el enlace ferroviario de la Almozara, y el nuevo torreâ”œâ”‚n y esquina noreste del palacio de la Aljaferâ”œÂ¡a. Al fondo, edificios del entorno de la calle Aljaferâ”œÂ¡a, y los grandes bloques recayentes al paseo de Marâ”œÂ¡a Agustin.', 1978, 1978, 1978, 'Anos 70', 'LA ALMOZARA', 41.65791800, -0.89996500, '0101000020E6100000B16D516683CCECBF91B932A836D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32381276634.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32381276634.webp', 'https://www.flickr.com/photos/zaragozaantigua/32381276634/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22756, 'Batalla de Arapiles 1978', 'Imagen del aspecto de la calle de la Batalla de los Arapiles cuando formaba parte del "limes" o frontera que marcaba el inicio del agreste oeste no urbanizado aâ”œâ•‘n en esta parte de la ciudad. Los grandes espacios ocupados por el "Tiro de Pichâ”œâ”‚n", el cuartel de Pontoneros, y los campos de fâ”œâ•‘tbol de los PP. Escolapios, en el entorno del camino de la Almozara, conformaban un formidable tapâ”œâ”‚n que, tras la recuperaciâ”œâ”‚n de la democracia municipal en 1979 fue en parte liberado, dando como resultado el nuevo ensanche de la Puerta de Sancho, acompaâ”œâ–’ado con su dotaciâ”œâ”‚n de servicios pâ”œâ•‘blicos. Asâ”œÂ¡, y justo a la derecha, en la zona delimitada por un muro con alambrada, serâ”œÃ­ luego levantado el actual Colegio Pâ”œâ•‘blico de Educaciâ”œâ”‚n Infantil y Primaria "Puerta de Sancho", y el Centro Deportivo Municipal "La Almozara". En la imagen, la calle muestra su acera en versiâ”œâ”‚n "mono" (sâ”œâ”‚lo en un lado), con su inmediato y natural embalsamiento de agua como espacio de chapoteo. Al fondo, visual insâ”œâ”‚lita de las traseras de los bloques sitos en las mâ”œÃ­s altas calles Râ”œÂ¡o Cinca, y Ribagorza. Fuente visual: Banco de Imâ”œÃ­genes/Asociaciâ”œâ”‚n de Vecinos Barrio de San Josâ”œÂ®, amablemente cedida para el', 1978, 1978, 1978, 'Anos 70', 'LA ALMOZARA', 41.66267900, -0.89921400, '0101000020E6100000FA5E43705CC6ECBF7C5F5CAAD2D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32783742850.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32783742850.webp', 'https://www.flickr.com/photos/zaragozaantigua/32783742850/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22759, 'Almozara 1978', 'Imagen del humanizado paisaje en torno al enlace ferroviario de la Almozara que comunicaba, por el puente del ferrocarril, al fondo, con la Estaciâ”œâ”‚n del Norte. A la izquierda, la gran instalaciâ”œâ”‚n de la Industrial Quâ”œÂ¡mica, y una improvisada (y concurrida) rinconera o solanera allâ”œÂ¡ habilitada. Al fondo, modernos bloques de la esquina de la calle de Santa Lucia. En el centro de la imagen, unas seâ”œâ–’oras cruzan las vâ”œÂ¡as provenientes del terraplâ”œÂ®n de la derecha. Entre ellas y los tertulianos, al fondo, unos pardales se aventuran por parajes inciertos, y atractivos. Se destaca por encima la silueta de la Compaâ”œâ–’â”œÂ¡a Industrial Aragonesa, y a su derecha, de las naves de la fâ”œÃ­brica y talleres de Simâ”œâ”‚n Loscertales SA, en la calle de la Aljaferâ”œÂ¡a. Mâ”œÃ­s al fondo, los grandes bloques recayentes al paseo de Marâ”œÂ¡a Agustin. El Palacio de la Aljaferâ”œÂ¡a, fuera de plano, queda justo a la derecha. Fuente visual: Banco de Imâ”œÃ­genes/Asociaciâ”œâ”‚n de Vecinos Barrio de San Josâ”œÂ®, amablemente cedida para el', 1978, 1978, 1978, 'Anos 70', 'LA ALMOZARA', 41.65800300, -0.89650100, '0101000020E6100000FA997ADD22B0ECBFBFD53A7139D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32826164320.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32826164320.webp', 'https://www.flickr.com/photos/zaragozaantigua/32826164320/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22767, 'Av. Pablo Gargallo 1978', 'Imagen del ingreso principal a la Industrial Quâ”œÂ¡mica desde la avenida de Pablo Gargallo, a la altura del antiguo despartidero que tambiâ”œÂ®n daba acceso al camino de la Almozara. Al fondo, bloques del paseo de Marâ”œÂ¡a Agustâ”œÂ¡n. La gran pintada mural de la imagen hacâ”œÂ¡a referencia al acuerdo alcanzado por la empresa, el comitâ”œÂ® de trabajadores, y el sindicato CCOO, que incluâ”œÂ¡a el final pactado y gradual de las tradicionales emanaciones del tâ”œâ”‚xico diâ”œâ”‚xido de azufre sobre los residentes del barrio de la Almozara.', 1978, 1978, 1978, 'Anos 70', 'LA ALMOZARA', 41.65956100, -0.89400000, '0101000020E6100000CFF753E3A59BECBFC85BAE7E6CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33229026456.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33229026456.webp', 'https://www.flickr.com/photos/zaragozaantigua/33229026456/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22851, 'Râ”œÂ¡o Ebro 1985', 'Desolaciâ”œâ”‚n e insolaciâ”œâ”‚n en la "playa" de la margen derecha, en el barrio de la Quâ”œÂ¡mica de Zaragoza, a orillas del râ”œÂ¡o Ebro. La denominaciâ”œâ”‚n de "Playa de los â”œÃ¼ngeles" se le ha dado a esta zona del cauce durante el siglo XX, tanto a la orilla que vemos como a la de enfrente, en Ranillas. Al fondo, puente del ferrocarril o de la Almozara, con el Pilar y San Pablo sobresaliendo.', 1985, 1985, 1985, 'Anos 80', 'LA ALMOZARA', 41.66295500, -0.89296200, '0101000020E61000009A43520B2593ECBF1EDC9DB5DBD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15238664083.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15238664083.webp', 'https://www.flickr.com/photos/zaragozaantigua/15238664083/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22925, 'La Almozara 1981', 'Imagen del antiguo despartidero entre el camino de Monzalbarba, luego avenida de Pablo Gargallo (a la izquierda), y el camino de la Almozara, luego avenida homâ”œâ”‚nima (a la derecha). A la izquierda, instalaciones de la polâ”œÂ®mica Industrial Quâ”œÂ¡mica de Zaragoza. La publicitaria isleta del centro luego darâ”œÂ¡a paso a una rotonda y arbolada zona donde en los aâ”œâ–’os 90 se instalarâ”œÂ¡a el Homenaje a la Puerta de Sancho. Hacia el fondo, pioneros bloques de la zona y grâ”œâ•‘as de obra.', 1981, 1981, 1981, 'Anos 80', 'LA ALMOZARA', 41.66000100, -0.89487500, '0101000020E6100000894160E5D0A2ECBFE529ABE97AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30140122534.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30140122534.webp', 'https://www.flickr.com/photos/zaragozaantigua/30140122534/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22951, 'C.â”¬â•‘ de la Almozara c.1981', 'Imagen capturada en el camino de la Almozara desde poco despuâ”œÂ®s de la calle de la Batalla de Arapiles, que entonces seâ”œâ–’alaba el "nec plus ultra" urbano en esta parte del homâ”œâ”‚nimo barrio. A la derecha, muros del que fuera primer moderno colegio de EGB de la Almozara (inaugurado para el curso acadâ”œÂ®mico 1972-73), todavâ”œÂ¡a con los provisionales barracones habilitados durante las obras de construcciâ”œâ”‚n. Aâ”œâ–’os mâ”œÃ­s tarde serâ”œÂ¡a objeto de una ampliaciâ”œâ”‚n mediante la adiciâ”œâ”‚n de un nuevo cuerpo esquinero, a la derecha de la imagen. En la actualidad, este centro se denomina CEIP Jerâ”œâ”‚nimo Zurita Castro. El antiguo camino de la Almozara serâ”œÂ¡a redenominado poco despuâ”œÂ®s como avenida, y como tal serâ”œÂ¡a objeto de una moderna urbanizaciâ”œâ”‚n. Justo enfrente del colegio, al otro lado de la avenida, se levantarâ”œÂ¡a el Centro Deportivo Municipal la Almozara. Al fondo, densa foresta del antiguo cuartel de Pontoneros de la Almozara que tras la Operaciâ”œâ”‚n Cuarteles habâ”œÂ¡a sido reconvertido en el privado Centro Deportivo Militar "El Soto". Hacia la derecha, fuera de plano, se encontraban las instalaciones de la Sociedad Deportiva "Tiro de Pichâ”œâ”‚n". La urgente construcciâ”œâ”‚n de este colegio de EGB al comienzo de la dâ”œÂ®cada de los aâ”œâ–’os setenta se realizâ”œâ”‚ en unos baratos terrenos que, entre otras cosas, lo eran por estar muy cerca del râ”œÂ¡o Ebro y apenas cuatro metros por encima de la cota de la orilla, es decir que son naturalmente susceptibles de inundarse cada vez que el râ”œÂ¡o se sale de madre. Cuando esto sucede (como por ejemplo, durante la penâ”œâ•‘ltima avenida en el aâ”œâ–’o 2015), el agua anega el entorno del colegio y las clases deben ser suspendidas. Fuente visual: laalmozara.blogspot.com.es/', 1981, 1981, 1981, 'Anos 80', 'LA ALMOZARA', 41.66356000, -0.89904300, '0101000020E6100000CA5356D3F5C4ECBF8577B988EFD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40244036705.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40244036705.webp', 'https://www.flickr.com/photos/zaragozaantigua/40244036705/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23046, 'Plaza de Europa 1992', 'Simpâ”œÃ­tico dibujo para la portada del programa de fiestas del barrio de La Almozara centrado en un enorme cartelâ”œâ”‚n anunciador de las mismas que pende del obelisco levantado en el centro de la nueva plaza de Europa e inaugurado a comienzos de 1990. Junto a â”œÂ®l, una banda de mâ”œâ•‘sica sobre vertiginosa plataforma ameniza el paso de la comparsa de Gigantes y Cabezudos acompaâ”œâ–’ada del bullicio que le es consustancial. Esta gran estructura de 35 metros de altura realizada en hormigâ”œâ”‚n revestido de mâ”œÃ­rmol de Marquina (Vizcaya) triunfâ”œâ”‚ sobre propuestas variopintas, como recrear la columna de la Virgen del Pilar, y una recurrente fuente ornamental. La singularidad o rareza de este monumento, cuyos orâ”œÂ¡genes histâ”œâ”‚ricos se remontan al antiguo Egipto como homenaje al dios Ra, tal vez expliquen el platillo volante que sobrevuela la escena como sugiriendo que se trata de una "marcianada", aunque durante los duros dâ”œÂ¡as caniculares, cuando ni el obelisco da sombra, el triunfo del sol en esta dura plaza es total.', 1992, 1992, 1992, 'Anos 90', 'LA ALMOZARA', 41.65931800, -0.89248800, '0101000020E61000007E5182FE428FECBF02D53F8864D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50432820713.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50432820713.webp', 'https://www.flickr.com/photos/zaragozaantigua/50432820713/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23087, 'Pasarela del Voluntariado 2007', 'Construcciâ”œâ”‚n de la Pasarela del Voluntariado, conocida popularmente como "El Pincho", en las inmediaciones de la Expo 2008 de Zaragoza. Es obra de Javier Manterola y une los barrios del Actur y La Almozara. Fuente: picasaweb.google.com/CHELUYS', 2007, 2007, 2007, 'Siglo XXI', 'LA ALMOZARA', 41.66528000, -0.89471000, '0101000020E6100000E1EEACDD76A1ECBF695721E527D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19778896350.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19778896350.webp', 'https://www.flickr.com/photos/zaragozaantigua/19778896350/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23146, 'Puente Almozara 2006', 'Foto: Pedro Etura. Vista en 2006 del puente de La Almozara desde la ribera del Ebro junto a la avenida de Ranillas, con el camino que en 2008 cambiarâ”œÃ­ su aspecto. Al fondo, la torre de San Pablo y la câ”œâ•‘pula de Santiago. Fuente: Heraldo de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', 'LA ALMOZARA', 41.66252900, -0.89064500, '0101000020E6100000C7116BF12980ECBF67D311C0CDD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31970176333.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31970176333.webp', 'https://www.flickr.com/photos/zaragozaantigua/31970176333/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24167, 'Apeadero de la Quâ”œÂ¡mica c.1973', 'Apeadero ferroviario de La Quâ”œÂ¡mica para viajeros y mercancâ”œÂ¡as, que debâ”œÂ¡a su nombre a la inmediata Industrial Quâ”œÂ¡mica. A la izquierda, el paso a nivel hacia el barrio de La Almozara o Paso de la Quâ”œÂ¡mica, con vehâ”œÂ¡culos que desde la avenida de Pablo Gargallo se encaminan hacia el paseo de Marâ”œÂ¡a Agustâ”œÂ¡n, el de Echegaray y Caballero, y la calle de Santa Ana. Hacia el fondo, las vâ”œÂ¡as conducen hasta el puente del Ferrocarril, y la vista alcanza hasta las verticales obras de construcciâ”œâ”‚n de la urbanizaciâ”œâ”‚n Kasan. Este paso fue durante mucho tiempo el â”œâ•‘nico punto de acceso al barrio de la Quâ”œÂ¡mica, problema agravado por el creciente parque automovilâ”œÂ¡stico que propiciâ”œâ”‚ que en este punto se escenificara el estrangulamiento de la circulaciâ”œâ”‚n viaria hacia ese barrio. Pocos aâ”œâ–’os despuâ”œÂ®s el trâ”œÃ­fico ferroviario fue suprimido, y este entorno radicalmente modificado.', 1973, 1973, 1973, 'Anos 70', 'LA ALMOZARA', 41.65980200, -0.89208700, '0101000020E6100000DFF94509FA8BECBFEEEA556474D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14753354398.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14753354398.webp', 'https://www.flickr.com/photos/zaragozaantigua/14753354398/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24168, 'Paso a Nivel Quâ”œÂ¡mica c.1969', 'Paso a nivel del Barrio de la Quâ”œÂ¡mica. Colecciâ”œâ”‚n: Junta Distrito Almozara. Archivo: Asociaciâ”œâ”‚n Paso a nivel. El paso a nivel fue durante aâ”œâ–’os la â”œâ•‘nica entrada al barrio de la Almozara desde "el centro". Tenia una anchura de cinco metros, con riesgos parea la parte mâ”œÃ­s vulnerable de quienes transitaban: los peatones. Como en todo paso a nivel (los habâ”œÂ¡a a cientos en todo el paâ”œÂ¡s) las barreras para el paso del ferrocarril marcaban el ritmo del trâ”œÃ­nsito. Las vâ”œÂ¡as desaparecieron en el aâ”œâ–’o 1976, cuando RENFE puso en marcha otros enlaces ferroviarios entre estaciones, y el Puente de la Almozara dejâ”œâ”‚ de cumplir la funciâ”œâ”‚n para la que fue construido (el puente del ferrocarril). Imagen tomada en lo que hoy en dâ”œÂ¡a es la plaza de Europa. Al fondo, la actual avenida de la Almozara.', 1969, 1969, 1969, 'Anos 60', 'LA ALMOZARA', 41.65975900, -0.89189800, '0101000020E610000015C5ABAC6D8AECBFEF1EA0FB72D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14776868187.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14776868187.webp', 'https://www.flickr.com/photos/zaragozaantigua/14776868187/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24173, 'Paso a nivel Almozara 1975', 'AYUNTAMIENTO DE ZARAGOZA/Sancho Ramo, Gerardo/23 enero 1975. Desde 1870 a 1976 el Puente de la Almozara sobre el râ”œÂ¡o Ebro funcionâ”œâ”‚ como importante punto de conexiâ”œâ”‚n ferroviaria de la ciudad, entre la Estaciâ”œâ”‚n del Norte, y la de Campo Sepulcro (luego se aâ”œâ–’adiâ”œâ”‚ la de Delicias). Fue profundamente remodelado varias veces, llegando a tener doble vâ”œÂ¡a. Con la entrada en funcionamiento de la Estaciâ”œâ”‚n de Miraflores, al sureste, el trâ”œÃ­nsito ferroviario Madrid-Barcelona ya podâ”œÂ¡a hacerse directamente sin pasar por este punto, y en 1976, finalmente, dejaron de pasar trenes. El puente fue remodelado para abrirse al trâ”œÃ­fico rodado con motor de explosiâ”œâ”‚n. En la imagen, el doble tendido ferroviario en un momento de cruce de vehâ”œÂ¡culos, a pocos metros de la actual Plaza de Europa, y un poco antes de la subestaciâ”œâ”‚n elâ”œÂ®ctrica "Elevaciâ”œâ”‚n de agua", junto al arranque del Puente de la Amozara. Esta instalaciâ”œâ”‚n aâ”œâ•‘n perdura hoy. A la derecha, el apeadero de la "Industrial Quâ”œÂ¡mica". Al fondo, imponentes, los recientes edificios KASAN (aâ”œâ–’o 1974), pioneros de la ACTUR.', 1975, 1975, 1975, 'Anos 70', 'LA ALMOZARA', 41.65965500, -0.89175400, '0101000020E61000004B7842AF3F89ECBF4AD235936FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14852272125.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14852272125.webp', 'https://www.flickr.com/photos/zaragozaantigua/14852272125/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24177, 'Paso a nivel Quâ”œÂ¡mica 1967', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. Octubre 1967. Deslumbrante paso de un tren por el paso a nivel sin barrera de la Quâ”œÂ¡mica. Al fondo, silueta brumosa de la mole de "Piensos Cia" y el acceso ferroviario a la industrial Quâ”œÂ¡mica. Mientras, peatones y ciclista esperan el paso.', 1967, 1967, 1967, 'Anos 60', 'LA ALMOZARA', 41.65975900, -0.89189800, '0101000020E610000015C5ABAC6D8AECBFEF1EA0FB72D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15048921638.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15048921638.webp', 'https://www.flickr.com/photos/zaragozaantigua/15048921638/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24250, 'Lorenzo Almarza 1914', 'Fotografâ”œÂ¡a autocroma con autorretrato del teniente Lorenzo Almarza Mallaâ”œÂ¡na realizado en el interior del Cuartel de Ingenieros y Pontoneros de Zaragoza, posiblemente en la Escuela Prâ”œÃ­ctica del camino de La Almozara. Este riojano de nacimiento (1887) siguiâ”œâ”‚ la carrera militar de su padre y se especializâ”œâ”‚ en el Cuerpo de Ingenieros. Aficionado a la fotografâ”œÂ¡a, fue adquiriendo experiencia en las sucesivas provincias por las que fue pasando en funciâ”œâ”‚n de su carrera. En 1913 llegâ”œâ”‚ destinado a Zaragoza, donde conociâ”œâ”‚ a quien serâ”œÂ¡a su esposa: Carmen Laguna de Rins y Ortiz. Este autorretrato fue capturado pocos dâ”œÂ¡as antes de su boda en la iglesia de Santa Engracia. De su estancia en la ciudad en esta â”œÂ®poca nos ha quedado un puâ”œâ–’ado de interesantes fotografâ”œÂ¡as, la mayor parte de las cuales tenemos incorporadas en el Gran Archivo Zaragoza Antigua.', 1914, 1914, 1914, 'Anos 10', 'LA ALMOZARA', 41.66600300, -0.90212300, '0101000020E61000006405BF0D31DEECBFDA0418963FD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49658282633.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49658282633.webp', 'https://www.flickr.com/photos/zaragozaantigua/49658282633/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24549, 'Voladura CIA 1992', 'El 29 de octubre de 1992, a las 17:00 h. se procediâ”œâ”‚ a derribar la factorâ”œÂ¡a de piensos CIA (Compaâ”œâ–’â”œÂ¡a Industria Agrâ”œÂ¡cola) de La Almozara. Este fue el resultado del primer fallido intento, que a pesar de las explosiones controladas sâ”œâ”‚lo pudo inclinar la estructura ante el regocijo del pâ”œâ•‘blico que se dio cita para contemplar el evento. Dâ”œÂ¡as despuâ”œÂ®s, cargas mâ”œÃ­s potentes derribaron finalmente esta fâ”œÃ­brica.', 1992, 1992, 1992, 'Anos 90', 'LA ALMOZARA', 41.65822300, -0.89620200, '0101000020E61000006B8313D1AFADECBFCD3CB9A640D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14864317886.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14864317886.webp', 'https://www.flickr.com/photos/zaragozaantigua/14864317886/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24557, 'Camino de la Almozara 1987', 'Inicio del camino de la Almozara (izquierda) del barrio homâ”œâ”‚nimo de Zaragoza, en la primavera de 1987. Fuente: www.facebook.com/photo.php?fbid=1486032505030913&set=...', 1987, 1987, 1987, 'Anos 80', 'LA ALMOZARA', 41.65984500, -0.89375600, '0101000020E61000002252D32EA699ECBFEDB60BCD75D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21107764179.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21107764179.webp', 'https://www.flickr.com/photos/zaragozaantigua/21107764179/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24755, 'Expo 2008', 'Vista parcial de la Exposiciâ”œâ”‚n Internacional de Zaragoza, durante su celebraciâ”œâ”‚n en 2008. Al fondo, barrio del Actur , el Pilar y la Seo. Fuente: Wikipedia', 2008, 2008, 2008, 'Siglo XXI', 'LA ALMOZARA', 41.66806800, -0.89912100, '0101000020E6100000B7B2446799C5ECBF87C0914083D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19345408094.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19345408094.webp', 'https://www.flickr.com/photos/zaragozaantigua/19345408094/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24760, 'Plazas temâ”œÃ­ticas Expo 2008', 'Construcciâ”œâ”‚n de los edificios de las plazas temâ”œÃ­ticas de la Expo 2008 de Zaragoza. En primer tâ”œÂ®rmino, Agua Extrema; detrâ”œÃ­s, El Faro, conocido como El Botijo; a la izquierda, Sed; detrâ”œÃ­s, Ciudades del Agua. Todos fueron derribados, excepto Sed: ahora es la Câ”œâ•‘pula del Milenio, en Valladolid. Fuente: picasaweb.google.com/CHELUYS', 2008, 2008, 2008, 'Siglo XXI', 'LA ALMOZARA', 41.66806800, -0.89912100, '0101000020E6100000B7B2446799C5ECBF87C0914083D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19941334726.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19941334726.webp', 'https://www.flickr.com/photos/zaragozaantigua/19941334726/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24792, 'Agua compartida 2008', 'En la Exposiciâ”œâ”‚n Internacional "Agua y desarrollo sostenible" de Zaragoza, habâ”œÂ¡a un conjunto de pabellones menores que se repartâ”œÂ¡an en un espacio denominado "plazas temâ”œÃ­ticas". Este es el llamado "Agua compartida", en un incendio durante su construcciâ”œâ”‚n, en mayo de 2008. Su contenido expositivo pretendâ”œÂ¡a "transmitir las implicaciones y oportunidades que ofrece el concepto de cuenca hidrolâ”œâ”‚gica como unidad de gestiâ”œâ”‚n para relacionarnos con el medio fâ”œÂ¡sico de forma mâ”œÃ­s solidaria", o eso decâ”œÂ¡an. Fuente: Heraldo de Aragâ”œâ”‚n.', 2008, 2008, 2008, 'Siglo XXI', 'LA ALMOZARA', 41.66790700, -0.89812300, '0101000020E6100000102219726CBDECBF7EE200FA7DD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32386366510.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32386366510.webp', 'https://www.flickr.com/photos/zaragozaantigua/32386366510/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24820, 'Puente de La Almozara 1992', 'El puente de La Almozara, antiguo del Ferrocarril, en una vista tomada desde la plaza de Europa, con los altos edificios de la margen izquierda al fondo. En su remodelaciâ”œâ”‚n integral de 1986, a cargo de Javier Manterola, se incluyâ”œâ”‚ el pasillo central abovedado con terminaciâ”œâ”‚n en plâ”œÃ­stico que centra la foto, para albergar tuberâ”œÂ¡as y cableado. En 2009, este elemento se sustituyâ”œâ”‚ por un paso peatonal con carril bici.', 1992, 1992, 1992, 'Anos 90', 'LA ALMOZARA', 41.66040500, -0.89139400, '0101000020E61000005038BBB54C86ECBFB48EAA2688D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50206518783.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50206518783.webp', 'https://www.flickr.com/photos/zaragozaantigua/50206518783/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24857, 'Embarcadero Ranillas 2008', 'Foto: Juan Carlos Leâ”œâ”‚n. En junio de 2008, con la Expo abierta dos semanas antes, se volviâ”œâ”‚ a montar el tinglado del embarcadero para los barcos de paseo que habâ”œÂ¡an de llegar hasta allâ”œÂ¡ desde Vadorrey, porque habâ”œÂ¡a sido arrastrado por el Ebro unos meses antes. A final de mes, los barcos empezaron sus viajes, pero sâ”œâ”‚lo llegaban hasta el puente de Piedra, punto hasta el que el azud garantizaba una lâ”œÃ­mina de agua (cuando tuvo uso). En julio, ya colocados los dos pantalanes en la orilla, se procediâ”œâ”‚ a dragar el râ”œÂ¡o para evitar que los barcos encallaran. Pero draga que te draga, nunca era suficiente. Por fin, el 9 de agosto comenzaron los viajes regulares hasta allâ”œÂ¡, que dejaron de producirse con el fin de la muestra. El embarcadero acabâ”œâ”‚ roto y abandonado. En la imagen, un Ebrobâ”œâ•‘s en pruebas, el 18 de julio, con el embarcadero a la derecha y el recinto de la Expo al fondo. Fuente: Heraldo de Aragâ”œâ”‚n.', 2008, 2008, 2008, 'Siglo XXI', 'LA ALMOZARA', 41.66668900, -0.89616000, '0101000020E6100000AF777FBC57ADECBF2DCDAD1056D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31982785844.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31982785844.webp', 'https://www.flickr.com/photos/zaragozaantigua/31982785844/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25529, 'Playa de San Rafael c.1983', 'La avenida de Ranillas albergando un remedo hollywoodiense en forma de cartel angelino. La denominaciâ”œâ”‚n de "los â”œÃ¼ngeles" ha sido dada a lo largo del siglo XX a las "playas" situadas en esta zona, en ambas mâ”œÃ­rgenes, aunque la original estaba en la margen derecha y â”œÂ®sta de la margen izquierda se diese en llamar playa de San Rafael.', 1983, 1983, 1983, 'Anos 80', 'LA ALMOZARA', 41.66330400, -0.89087500, '0101000020E6100000355EBA490C82ECBF2AA73D25E7D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14968409195.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14968409195.webp', 'https://www.flickr.com/photos/zaragozaantigua/14968409195/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26040, 'Playa de San Rafael c.1901', 'Dos baâ”œâ–’istas, captados desde la playa de San Rafael del râ”œÂ¡o Ebro, en Ranillas, junto al puente del Ferrocarril. Al fondo, en el centro, el cuartel de La Aljaferâ”œÂ¡a, con la chimenea de la Uniâ”œâ”‚n Alcoholera delante; a la derecha, la chimenea de la Industrial Quâ”œÂ¡mica. Fuente visual: Archivo Josep Maria Reitg Martâ”œÂ¡, Ajuntament de Girona', 1901, 1901, 1901, 'Anos 1900', 'LA ALMOZARA', 41.66295100, -0.89062600, '0101000020E610000017F4DE180280ECBFDDEC0F94DBD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31247188880.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31247188880.webp', 'https://www.flickr.com/photos/zaragozaantigua/31247188880/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21619, 'Gasolinera El Portazgo 1927', 'Zoilo Râ”œÂ¡os instalâ”œâ”‚ en 1927 un surtidor de gasolina de la petrolera El Clavileâ”œâ–’o en El Ventorrillo de San Lamberto, la tienda-bar de sus padres en El Portazgo, que en 1953 se convertirâ”œÂ¡a en estaciâ”œâ”‚n de servicio. Fuente: Colecciâ”œâ”‚n particular.', 1927, 1927, 1927, 'Anos 20', 'MIRALBUENO', 41.66057300, -0.92552500, '0101000020E61000003D2CD49AE69DEDBF70CFF3A78DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32834017090.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32834017090.webp', 'https://www.flickr.com/photos/zaragozaantigua/32834017090/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22159, 'Ctra. de Logroâ”œâ–’o 1959', 'Vista aâ”œÂ®rea del "poblado americano" proyectado para soldados y oficiales norteamericanos destinados a la Base Aâ”œÂ®rea de Zaragoza, junto a la carretera de Logroâ”œâ–’o. Al fondo y a la izquierda, el meandro de Ranillas. Fuente: TAF Helicâ”œâ–“pters. Arxiu Nacional de Catalunya.', 1959, 1959, 1959, 'Anos 50', 'MIRALBUENO', 41.66503900, -0.93017000, '0101000020E6100000DD0C37E0F3C3EDBF43C879FF1FD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30548881003.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30548881003.webp', 'https://www.flickr.com/photos/zaragozaantigua/30548881003/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23670, 'Icarsa 1965', 'Imagen capturada sobrevolando el entorno del arranque de la carretera de Logroâ”œâ–’o, que corta de izquierda a derecha, con el trazado del ferrocarril de Caminreal a la izquierda. En el centro, Industrial Carrocera Aragonesa, S.A., Icarsa, factorâ”œÂ¡a de carrozado de autobuses y autocares. Hacia la derecha, la Urbanizaciâ”œâ”‚n Torres de San Lamberto y su llamativa ordenaciâ”œâ”‚n alrededor de modernos "chalets" para los "americanos" (recibidos con alegrâ”œÂ¡a) de la base militar aâ”œÂ®rea. Al fondo, el sur geogrâ”œÃ­fico, con el camino del Pilâ”œâ”‚n y el gran cuartel del arma de aviaciâ”œâ”‚n de San Lamberto. En primer tâ”œÂ®rmino, junto al camino de la Mengranera, la alabeada parcela con chalet junto al depâ”œâ”‚sito de agua, donde en 1971 se construyâ”œâ”‚ el nuevo edificio del Colegio Alemâ”œÃ­n. Fuente visual: Arxiu Nacional de Catalunya', 1965, 1965, 1965, 'Anos 60', 'MIRALBUENO', 41.66368100, -0.92785000, '0101000020E6100000C5FEB27BF2B0EDBF00FDBE7FF3D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32021153971.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32021153971.webp', 'https://www.flickr.com/photos/zaragozaantigua/32021153971/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23724, 'Ctra. de Logroâ”œâ–’o 1965', 'Imagen capturada sobrevolando, en primer tâ”œÂ®rmino, la estratâ”œÂ®gica carretera de Logroâ”œâ–’o, con una densidad de trâ”œÃ­fico aâ”œâ•‘n modesta, y centrada en las nuevas instalaciones de "Industrias Plâ”œÃ­sticas Pascor S.A.". A la derecha, un pequeâ”œâ–’o pedazo de la gran planta productora del acumulador TUDOR en la avenida de Navarra, alabeada por el ferrocarril de Caminreal. En el centro, el antiguo y semicircular depâ”œâ”‚sito ferroviario de Delicias, con su placa giratoria. Debajo, el proyectado y no ejecutado "by-pass" ferroviario con la lâ”œÂ¡nea de Caminreal. Al fondo, el râ”œÂ¡o Ebro, y el râ”œâ•‘stico meandro de Ranillas. Fuente visual: Arxiu Nacional de Catalunya', 1965, 1965, 1965, 'Anos 60', 'MIRALBUENO', 41.66094100, -0.92578800, '0101000020E61000009AEFE0270EA0EDBFF3CAF5B699D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31929232736.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31929232736.webp', 'https://www.flickr.com/photos/zaragozaantigua/31929232736/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
