INSERT INTO public.photos VALUES (24832, 'Barrio Oliver 1931', '"Las parcelas del Cura", Zaragoza, 1931. Los terrenos de la torre de las Tiples, llamada asâ”œÂ¡ porque su propietaria era la cantante Pilar Pâ”œÂ®rez, fueron comprados por el sacerdote Manuel Oliver, quien dividiâ”œâ”‚ la zona y vendiâ”œâ”‚ los solares a familias obreras. La gâ”œÂ®nesis del "Barrio Oliver" constaba de 20 calles sin nombre, con casas unifamiliares de un piso construidas por sus propios habitantes. Fuente: Mâ”¬Â¬ Pilar Biel Ibâ”œÃ­â”œâ–’ez, Zaragoza y la industrializaciâ”œâ”‚n: la arquitectura industrial 1875-1926, IFC, 2004.', 1931, 1931, 1931, 'Anos 30', 'MIRALBUENO', 41.65966600, -0.94259600, '0101000020E6100000B0E42A16BF29EEBF3E247CEF6FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19038205474.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19038205474.webp', 'https://www.flickr.com/photos/zaragozaantigua/19038205474/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24835, 'Ctra. de Logroâ”œâ–’o 1963', 'Una de las viviendas del "poblado americano", "Unidad vecinal USAF", construidas junto a la carretera de Logroâ”œâ–’o en 1958 segâ”œâ•‘n proyecto de Luis Laorga y Josâ”œÂ® Lâ”œâ”‚pez Zanâ”œâ”‚n. Fueron alojamiento de militares estadounidenses que desarrollaban sus actividades en la base aâ”œÂ®rea. La urbanizaciâ”œâ”‚n se sitâ”œâ•‘a junto a la carretera de Logroâ”œâ–’o, a la altura de la gasolinera Miralbueno.', 1963, 1963, 1963, 'Anos 60', 'MIRALBUENO', 41.66503900, -0.93017000, '0101000020E6100000DD0C37E0F3C3EDBF43C879FF1FD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22788341037.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22788341037.webp', 'https://www.flickr.com/photos/zaragozaantigua/22788341037/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22731, 'Pikolin 1973', 'Imagen capturada durante la inauguraciâ”œâ”‚n oficial del nuevo complejo industrial de la empresa colchonera Pikolin en la carretera de Logroâ”œâ–’o, durante la intervenciâ”œâ”‚n de su presidente, Alfonso Solâ”œÃ­ns Serrano, al mismo tiempo concejal del ayuntamiento de la ciudad. Como telâ”œâ”‚n de fondo, la singular y referencial torre del complejo, cuyo diseâ”œâ–’o fue obra del arquitecto â”œÃ¼ngel Colâ”œÃ­s Pareja. Fuente visual: www.pikolin.com/', 1973, 1973, 1973, 'Anos 70', 'VENTA DEL OLIVAR', 41.67434000, -0.95179600, '0101000020E6100000F1D58EE21C75EEBF3C31EBC550D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31058253953.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31058253953.webp', 'https://www.flickr.com/photos/zaragozaantigua/31058253953/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22810, 'Pikolin 1973', 'Imagen aâ”œÂ®rea del conjunto fabril de la fâ”œÃ­brica de colchones Pikolin reciâ”œÂ®n inaugurado en el kilâ”œâ”‚metro 3 de la carretera de Logroâ”œâ–’o, en el que destaca su referencial torre en forma de "seta gigante" entre la moderna zona expositiva y de oficinas proyectada por el arquitecto â”œÃ¼ngel Colâ”œÃ­s Pareja. Tras ella, las naves de producciâ”œâ”‚n, que con el tiempo mâ”œÃ­s que duplicarâ”œÃ­n la original superficie de 36.000m2, hasta que en 2008 la empresa anunciâ”œâ”‚ su traslado al polâ”œÂ¡gono PLA-ZA, completado en 2017.', 1973, 1973, 1973, 'Anos 70', 'VENTA DEL OLIVAR', 41.67453800, -0.95209800, '0101000020E6100000C5C892399677EEBF62F4DC4257D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51545483089.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51545483089.webp', 'https://www.flickr.com/photos/zaragozaantigua/51545483089/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23764, 'Pikolin 2008', 'Vista aâ”œÂ®rea, difundida en octubre de 2008, de la fâ”œÃ­brica de colchones Pikolin en el km. 6,5 de la carretera de Logroâ”œâ–’o (polâ”œÂ¡gono El Portazgo, barrio rural de la Venta del Olivar). Fue inaugurada en 1973, por traslado de las instalaciones junto al puente de Hierro, que se ubicaban allâ”œÂ¡ desde 1959. Esta empresa, propiedad de Alfonso Solâ”œÃ­ns, iniciâ”œâ”‚ sus actividades en 1948 con una fâ”œÃ­brica de camas de latâ”œâ”‚n. En 2008, la empresa anuncia su traslado al polâ”œÂ¡gono industrial PLAZA, y el subsiguiente plan de reconversiâ”œâ”‚n de los terrenos de la foto en un macro complejo comercial de productos en liquidaciâ”œâ”‚n ("outlet"), que se denominarâ”œÂ¡a Torre Village y se inaugurarâ”œÂ¡a en 2017. La nueva gran superficie comercial se sumarâ”œÂ¡a a las 12 preexistentes, continuando el modelo de crecimiento insostenible que caracteriza a la ciudad. Durante la legislatura 2015-2019 el Ayuntamiento gestionado por Zaragoza en Comâ”œâ•‘n, con el apoyo de CHA, opuso resistencia a la apertura de este "outlet", en la medida de sus posibilidades. En febrero de 2919, el Tribunal Superior de Justicia de Aragâ”œâ”‚n (TSJA) anulâ”œâ”‚ el plan especial por el que se fijaba la ordenaciâ”œâ”‚n de los suelos del previsto complejo comercial. El nuevo gobierno de la ciudad emanado de las elecciones municipales del 26 de mayo de 2019, compuesto por la derecha liberal de PP y C''s, râ”œÃ­pidamente ha puesto en marcha una modificaciâ”œâ”‚n aislada, a la carta, del Plan General de Ordenaciâ”œâ”‚n Urbana (PGOU) para dar respaldo a la continuidad del proyecto.', 2008, 2008, 2008, 'Siglo XXI', 'VENTA DEL OLIVAR', 41.67383200, -0.95111200, '0101000020E61000002EA9DA6E826FEEBFC77F812040D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24872974940.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24872974940.webp', 'https://www.flickr.com/p